import { createAuthClient } from "better-auth/vue"

// `useSession()` is browser-only — server callers (middleware, plugins) must
// pass `fetchOptions.headers` to `getSession()` so the request's cookies reach
// the auth endpoint.
//
// On the server we also have to give the client an absolute `baseURL`. The
// browser resolves better-auth's default relative URLs against
// `window.location.origin`; Node's native `fetch` does not, and would throw
// `Failed to parse URL from /api/auth/get-session` the moment any SSR
// middleware (require-auth, require-onboard) tries to read the session.
// `useRequestURL()` reads h3's request including x-forwarded-* headers, so
// preview and proxied environments resolve correctly without env config.

let _clientSingleton: ReturnType<typeof createAuthClient> | undefined

export function useAuth() {
  if (import.meta.server) {
    return createAuthClient({ baseURL: useRequestURL().origin })
  }
  if (!_clientSingleton) _clientSingleton = createAuthClient()
  return _clientSingleton
}

import { describe, expect, it } from "vitest"

import { pickInstallVersion, type VersionCandidate } from "./record"

const makeCandidate = (
  version: string,
  publishedAt: Date | null = null,
): VersionCandidate => ({
  version,
  publishedAt,
  createdAt: new Date("2026-01-01T00:00:00Z"),
})

describe("pickInstallVersion", () => {
  it("returns the requested version verbatim (passthrough) regardless of candidates", () => {
    const result = pickInstallVersion({
      requested: "1.2.3",
      candidates: [makeCandidate("9.9.9")],
    })
    expect(result).toEqual({ ok: true, version: "1.2.3" })
  })

  it("returns the requested version even when candidates is empty (passthrough trust)", () => {
    const result = pickInstallVersion({
      requested: "1.2.3",
      candidates: [],
    })
    expect(result).toEqual({ ok: true, version: "1.2.3" })
  })

  it("returns the first candidate when no version is requested", () => {
    const result = pickInstallVersion({
      requested: undefined,
      candidates: [
        makeCandidate("2.0.0", new Date("2026-03-01T00:00:00Z")),
        makeCandidate("1.0.0", new Date("2026-01-01T00:00:00Z")),
      ],
    })
    expect(result).toEqual({ ok: true, version: "2.0.0" })
  })

  it("returns no_published_version error when no version is requested and there are no candidates", () => {
    const result = pickInstallVersion({
      requested: undefined,
      candidates: [],
    })
    expect(result).toEqual({ ok: false, error: "no_published_version" })
  })
})

