const BASE = "http://localhost:3000"
const DB = execSync(`grep -E '^DATABASE_URL=' .env | sed 's/DATABASE_URL=//; s/\"//g'`).toString().trim()
const q = (s) => execSync(`psql "${DB}" -tAc ${JSON.stringify(s)}`).toString().trim()
const ok = (c, m) => console.log(`${c ? "✅" : "❌"} ${m}`)

const browser = await chromium.launch()
const ctx = await browser.newContext({ acceptDownloads: true })
await ctx.request.post(`${BASE}/api/auth/sign-in/email`, { data: { email: "amy@agentcenter.dev", password: "verify12345" } })
const page = await ctx.newPage()

// reset amy's ext-1 install state for a clean double-count measurement
execSync(`psql "${DB}" -c "delete from installs where user_id='user-amy' and extension_id='ext-1'; delete from collection_items ci using collections c where ci.collection_id=c.id and ci.extension_id='ext-1' and c.owner_user_id='user-amy' and c.system_kind='installed'; update extensions set downloads_count=248700 where id='ext-1';" >/dev/null`)

await page.goto(`${BASE}/en/extensions/web-search-pro`, { waitUntil: "networkidle" })
await page.getByRole("button", { name: "Account menu" }).waitFor({ timeout: 10000 })

// --- 1. Direct download actually delivers a .zip ---
